const express = require('express');
const bcrypt = require('bcryptjs');
const pool = require('../lib/db');
const { generateToken, authMiddleware } = require('../lib/auth');

const router = express.Router();

// Register
router.post('/register', async (req, res) => {
  try {
    const { email, password, name, role = 'candidate', company_name } = req.body;

    if (!email || !password) {
      return res.status(400).json({ error: 'Email and password are required' });
    }

    // Check if user exists
    const existing = await pool.query('SELECT id FROM users WHERE email = $1', [email]);
    if (existing.rows.length > 0) {
      return res.status(400).json({ error: 'Email already registered' });
    }

    // Hash password
    const password_hash = await bcrypt.hash(password, 10);

    // Create user
    const result = await pool.query(
      `INSERT INTO users (email, password_hash, name, role, company_name)
       VALUES ($1, $2, $3, $4, $5)
       RETURNING id, email, name, role, company_name, created_at`,
      [email, password_hash, name, role, company_name]
    );

    const user = result.rows[0];
    const token = generateToken(user);

    res.json({
      success: true,
      user: { id: user.id, email: user.email, name: user.name, role: user.role },
      token
    });
  } catch (err) {
    console.error('Registration error:', err);
    res.status(500).json({ error: 'Registration failed' });
  }
});

// Login
router.post('/login', async (req, res) => {
  try {
    const { email, password } = req.body;

    if (!email || !password) {
      return res.status(400).json({ error: 'Email and password are required' });
    }

    const result = await pool.query('SELECT * FROM users WHERE email = $1', [email]);
    if (result.rows.length === 0) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const user = result.rows[0];
    const validPassword = await bcrypt.compare(password, user.password_hash);
    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = generateToken(user);
    req.session.token = token;

    res.json({
      success: true,
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
        is_paid: user.is_paid
      },
      token
    });
  } catch (err) {
    console.error('Login error:', err);
    res.status(500).json({ error: 'Login failed' });
  }
});

// Get current user
router.get('/me', authMiddleware, (req, res) => {
  res.json({
    user: {
      id: req.user.id,
      email: req.user.email,
      name: req.user.name,
      role: req.user.role,
      company_name: req.user.company_name,
      is_paid: req.user.is_paid,
      created_at: req.user.created_at
    }
  });
});

// Logout
router.post('/logout', (req, res) => {
  req.session.destroy();
  res.json({ success: true });
});

// Payment verification
router.get('/verify-payment', authMiddleware, async (req, res) => {
  try {
    const sessionId = req.query.session_id;
    if (!sessionId) {
      return res.status(400).json({ error: 'Session ID required' });
    }

    // Verify with Polsia
    const response = await fetch(
      `${process.env.POLSIA_API_URL || 'https://polsia.com/api/proxy/ai'}/api/company-payments/verify?session_id=${sessionId}`,
      { headers: { 'Authorization': `Bearer ${process.env.POLSIA_API_KEY}` } }
    );
    const { verified, payment } = await response.json();

    if (verified) {
      await pool.query(
        'UPDATE users SET is_paid = true, stripe_subscription_id = $1 WHERE id = $2',
        [payment.subscription_id || sessionId, req.user.id]
      );
      res.json({ success: true, verified: true });
    } else {
      res.json({ success: false, verified: false });
    }
  } catch (err) {
    console.error('Payment verification error:', err);
    res.status(500).json({ error: 'Verification failed' });
  }
});

module.exports = router;

// OmniScore Migration - Candidate Credit Score System
module.exports = {
  name: 'add_omniscore_tables',
  up: async (client) => {
    // OmniScore main table - stores current score and history
    await client.query(`
      CREATE TABLE IF NOT EXISTS omni_scores (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE UNIQUE,
        total_score INTEGER DEFAULT 300,
        interview_score INTEGER DEFAULT 0,
        technical_score INTEGER DEFAULT 0,
        resume_score INTEGER DEFAULT 0,
        behavior_score INTEGER DEFAULT 0,
        score_tier VARCHAR(50) DEFAULT 'new',
        last_updated TIMESTAMP DEFAULT NOW(),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Score components - individual score factors with time decay
    await client.query(`
      CREATE TABLE IF NOT EXISTS score_components (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        component_type VARCHAR(50) NOT NULL,
        source_type VARCHAR(50),
        source_id INTEGER,
        points INTEGER NOT NULL,
        max_points INTEGER NOT NULL,
        weight DECIMAL(3,2) DEFAULT 1.0,
        decay_rate DECIMAL(3,2) DEFAULT 0.95,
        metadata JSONB DEFAULT '{}',
        created_at TIMESTAMP DEFAULT NOW(),
        expires_at TIMESTAMP
      )
    `);

    // Score history - track score changes over time
    await client.query(`
      CREATE TABLE IF NOT EXISTS score_history (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        previous_score INTEGER,
        new_score INTEGER,
        change_amount INTEGER,
        change_reason VARCHAR(255),
        component_type VARCHAR(50),
        created_at TIMESTAMP DEFAULT NOW()
      )
    `);

    // Role-specific scores
    await client.query(`
      CREATE TABLE IF NOT EXISTS role_scores (
        id SERIAL PRIMARY KEY,
        user_id INTEGER REFERENCES users(id) ON DELETE CASCADE,
        role_name VARCHAR(100) NOT NULL,
        score INTEGER DEFAULT 300,
        interview_count INTEGER DEFAULT 0,
        last_updated TIMESTAMP DEFAULT NOW(),
        UNIQUE(user_id, role_name)
      )
    `);

    // Create indexes for performance
    await client.query(`
      CREATE INDEX IF NOT EXISTS idx_score_components_user ON score_components(user_id);
      CREATE INDEX IF NOT EXISTS idx_score_history_user ON score_history(user_id);
      CREATE INDEX IF NOT EXISTS idx_role_scores_user ON role_scores(user_id);
    `);

    console.log('OmniScore tables created successfully');
  }
};

