/* Variables */
:root {
  --bg-primary: #0a0a0f;
  --bg-secondary: #12121a;
  --bg-card: #1a1a24;
  --bg-elevated: #22222e;

  --text-primary: #f4f4f5;
  --text-secondary: #a1a1aa;
  --text-muted: #71717a;

  --accent-primary: #10b981;
  --accent-secondary: #34d399;
  --accent-gradient: linear-gradient(135deg, #10b981 0%, #06b6d4 100%);

  --border-color: #27272a;
  --border-light: #3f3f46;

  --font-display: 'Space Grotesk', sans-serif;
  --font-body: 'Inter', sans-serif;

  --radius-sm: 6px;
  --radius-md: 12px;
  --radius-lg: 20px;
  --radius-full: 9999px;

  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.3);
  --shadow-md: 0 4px 20px rgba(0, 0, 0, 0.4);
  --shadow-lg: 0 8px 40px rgba(0, 0, 0, 0.5);
  --shadow-glow: 0 0 40px rgba(16, 185, 129, 0.2);
}

/* Reset */
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
}

body {
  font-family: var(--font-body);
  background: var(--bg-primary);
  color: var(--text-primary);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
}

a {
  color: inherit;
  text-decoration: none;
}

ul {
  list-style: none;
}

/* Utility Classes */
.text-gradient {
  background: var(--accent-gradient);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}

/* Buttons */
.btn {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  padding: 12px 24px;
  font-family: var(--font-display);
  font-weight: 500;
  font-size: 15px;
  border-radius: var(--radius-full);
  border: none;
  cursor: pointer;
  transition: all 0.2s ease;
}

.btn-primary {
  background: var(--accent-gradient);
  color: #000;
  box-shadow: var(--shadow-glow);
}

.btn-primary:hover {
  transform: translateY(-2px);
  box-shadow: 0 0 60px rgba(16, 185, 129, 0.3);
}

.btn-ghost {
  background: transparent;
  color: var(--text-primary);
  border: 1px solid var(--border-light);
}

.btn-ghost:hover {
  background: var(--bg-elevated);
  border-color: var(--accent-primary);
}

.btn-large {
  padding: 16px 32px;
  font-size: 16px;
}

.btn-full {
  width: 100%;
}

/* Navigation */
.nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 100;
  padding: 16px 0;
  background: rgba(10, 10, 15, 0.8);
  backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border-color);
}

.nav-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 0 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.logo {
  display: flex;
  align-items: center;
  gap: 10px;
  font-family: var(--font-display);
  font-weight: 700;
  font-size: 22px;
}

.logo-icon {
  color: var(--accent-primary);
  font-size: 28px;
}

.nav-links {
  display: flex;
  gap: 32px;
}

.nav-links a {
  font-size: 14px;
  color: var(--text-secondary);
  transition: color 0.2s;
}

.nav-links a:hover {
  color: var(--text-primary);
}

.nav-auth {
  display: flex;
  gap: 12px;
}

/* Hero Section */
.hero {
  min-height: 100vh;
  padding: 140px 24px 80px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 80px;
  max-width: 1400px;
  margin: 0 auto;
}

.hero-content {
  flex: 1;
  max-width: 600px;
}

.hero-badge {
  display: inline-flex;
  padding: 8px 16px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-full);
  font-size: 14px;
  margin-bottom: 24px;
}

.hero h1 {
  font-family: var(--font-display);
  font-size: 64px;
  font-weight: 700;
  line-height: 1.1;
  margin-bottom: 24px;
}

.hero-subtitle {
  font-size: 20px;
  color: var(--text-secondary);
  margin-bottom: 40px;
}

.hero-cta {
  display: flex;
  gap: 16px;
  margin-bottom: 60px;
}

.hero-stats {
  display: flex;
  gap: 48px;
}

.stat {
  display: flex;
  flex-direction: column;
}

.stat-value {
  font-family: var(--font-display);
  font-size: 32px;
  font-weight: 700;
  color: var(--accent-primary);
}

.stat-label {
  font-size: 14px;
  color: var(--text-muted);
}

/* Hero Visual */
.hero-visual {
  flex: 1;
  max-width: 500px;
}

.interview-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  overflow: hidden;
  box-shadow: var(--shadow-lg);
}

.card-header {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 16px 20px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
  font-size: 13px;
  color: var(--text-muted);
}

.card-dots {
  display: flex;
  gap: 6px;
}

.card-dots span {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  background: var(--border-light);
}

.card-dots span:first-child { background: #ef4444; }
.card-dots span:nth-child(2) { background: #f59e0b; }
.card-dots span:last-child { background: #10b981; }

.card-content {
  padding: 24px;
}

.question-bubble {
  background: var(--bg-elevated);
  border-radius: var(--radius-md);
  padding: 20px;
  margin-bottom: 20px;
}

.ai-tag {
  display: inline-block;
  padding: 4px 10px;
  background: var(--accent-gradient);
  border-radius: var(--radius-full);
  font-size: 11px;
  font-weight: 600;
  color: #000;
  margin-bottom: 12px;
}

.question-bubble p {
  font-size: 15px;
  line-height: 1.6;
}

.response-area {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 16px;
  background: rgba(16, 185, 129, 0.1);
  border: 1px dashed var(--accent-primary);
  border-radius: var(--radius-md);
  font-size: 14px;
  color: var(--accent-secondary);
}

.typing-indicator {
  display: flex;
  gap: 4px;
}

.typing-indicator span {
  width: 8px;
  height: 8px;
  background: var(--accent-primary);
  border-radius: 50%;
  animation: typing 1.4s infinite;
}

.typing-indicator span:nth-child(2) { animation-delay: 0.2s; }
.typing-indicator span:nth-child(3) { animation-delay: 0.4s; }

@keyframes typing {
  0%, 60%, 100% { opacity: 0.3; transform: scale(0.8); }
  30% { opacity: 1; transform: scale(1); }
}

.card-footer {
  padding: 16px 24px;
  background: var(--bg-secondary);
  border-top: 1px solid var(--border-color);
  display: flex;
  justify-content: flex-end;
}

.score-preview {
  display: flex;
  align-items: baseline;
  gap: 4px;
}

.score-preview .score {
  font-family: var(--font-display);
  font-size: 28px;
  font-weight: 700;
  color: var(--accent-primary);
}

.score-preview .score-label {
  font-size: 16px;
  color: var(--text-muted);
}

/* Section Styles */
.section-header {
  text-align: center;
  margin-bottom: 60px;
}

.section-header h2 {
  font-family: var(--font-display);
  font-size: 42px;
  font-weight: 700;
  margin-bottom: 16px;
}

.section-header p {
  font-size: 18px;
  color: var(--text-secondary);
}

/* Features Section */
.features {
  padding: 100px 24px;
  max-width: 1200px;
  margin: 0 auto;
}

.feature-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 24px;
}

.feature-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 32px;
  transition: all 0.3s ease;
}

.feature-card:hover {
  border-color: var(--accent-primary);
  transform: translateY(-4px);
  box-shadow: var(--shadow-glow);
}

.feature-icon {
  font-size: 40px;
  margin-bottom: 20px;
}

.feature-card h3 {
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 600;
  margin-bottom: 12px;
}

.feature-card p {
  font-size: 15px;
  color: var(--text-secondary);
  line-height: 1.6;
}

/* How It Works */
.how-it-works {
  padding: 100px 24px;
  background: var(--bg-secondary);
}

.steps {
  max-width: 800px;
  margin: 0 auto;
  display: flex;
  flex-direction: column;
  gap: 48px;
}

.step {
  display: flex;
  gap: 32px;
  align-items: flex-start;
}

.step-number {
  font-family: var(--font-display);
  font-size: 48px;
  font-weight: 700;
  color: var(--accent-primary);
  line-height: 1;
  opacity: 0.5;
}

.step-content h3 {
  font-family: var(--font-display);
  font-size: 24px;
  font-weight: 600;
  margin-bottom: 8px;
}

.step-content p {
  font-size: 16px;
  color: var(--text-secondary);
}

/* Pricing Section */
.pricing {
  padding: 100px 24px;
  max-width: 900px;
  margin: 0 auto;
}

.pricing-cards {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 24px;
}

.pricing-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 40px;
  position: relative;
}

.pricing-card.featured {
  border-color: var(--accent-primary);
  box-shadow: var(--shadow-glow);
}

.pricing-badge {
  position: absolute;
  top: -12px;
  left: 50%;
  transform: translateX(-50%);
  padding: 6px 16px;
  background: var(--accent-gradient);
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 600;
  color: #000;
}

.pricing-header {
  text-align: center;
  margin-bottom: 32px;
}

.pricing-header h3 {
  font-family: var(--font-display);
  font-size: 24px;
  margin-bottom: 12px;
}

.price {
  font-family: var(--font-display);
  font-size: 48px;
  font-weight: 700;
}

.price span {
  font-size: 16px;
  font-weight: 400;
  color: var(--text-muted);
}

.pricing-features {
  margin-bottom: 32px;
}

.pricing-features li {
  padding: 12px 0;
  border-bottom: 1px solid var(--border-color);
  font-size: 15px;
}

.pricing-features li.disabled {
  color: var(--text-muted);
}

/* CTA Section */
.cta {
  padding: 100px 24px;
  background: var(--bg-secondary);
  text-align: center;
}

.cta-content {
  max-width: 600px;
  margin: 0 auto;
}

.cta h2 {
  font-family: var(--font-display);
  font-size: 42px;
  font-weight: 700;
  margin-bottom: 16px;
}

.cta p {
  font-size: 18px;
  color: var(--text-secondary);
  margin-bottom: 32px;
}

/* Footer */
.footer {
  padding: 60px 24px 24px;
  border-top: 1px solid var(--border-color);
}

.footer-content {
  max-width: 1200px;
  margin: 0 auto;
  display: flex;
  justify-content: space-between;
  margin-bottom: 48px;
}

.footer-brand p {
  color: var(--text-muted);
  margin-top: 12px;
  font-size: 14px;
}

.footer-links {
  display: flex;
  gap: 80px;
}

.footer-col h4 {
  font-family: var(--font-display);
  font-size: 14px;
  font-weight: 600;
  margin-bottom: 16px;
  color: var(--text-muted);
}

.footer-col a {
  display: block;
  font-size: 14px;
  color: var(--text-secondary);
  padding: 6px 0;
  transition: color 0.2s;
}

.footer-col a:hover {
  color: var(--text-primary);
}

.footer-bottom {
  max-width: 1200px;
  margin: 0 auto;
  padding-top: 24px;
  border-top: 1px solid var(--border-color);
  font-size: 13px;
  color: var(--text-muted);
}

/* OmniScore Styles */
.omniscore-preview {
  background: linear-gradient(135deg, var(--bg-card) 0%, #1a1a2e 100%);
}

.omniscore-display {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 24px;
}

.omniscore-circle {
  width: 160px;
  height: 160px;
  border-radius: 50%;
  background: conic-gradient(from 0deg, var(--accent-primary) 0%, #06b6d4 50%, var(--accent-primary) 100%);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  position: relative;
}

.omniscore-circle::before {
  content: '';
  position: absolute;
  width: 130px;
  height: 130px;
  border-radius: 50%;
  background: var(--bg-card);
}

.omniscore-value {
  position: relative;
  font-family: var(--font-display);
  font-size: 48px;
  font-weight: 700;
  color: var(--text-primary);
}

.omniscore-label {
  position: relative;
  font-size: 12px;
  color: var(--text-muted);
  text-transform: uppercase;
  letter-spacing: 1px;
}

.omniscore-breakdown {
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.score-factor {
  display: flex;
  justify-content: space-between;
  padding: 8px 12px;
  background: var(--bg-secondary);
  border-radius: var(--radius-sm);
  font-size: 13px;
}

.factor-score {
  color: var(--accent-primary);
  font-weight: 600;
}

.score-badge {
  padding: 6px 16px;
  border-radius: var(--radius-full);
  font-size: 14px;
  font-weight: 600;
}

.score-badge.excellent {
  background: var(--accent-gradient);
  color: #000;
}

.score-badge.good {
  background: rgba(16, 185, 129, 0.2);
  color: var(--accent-primary);
}

.score-badge.average {
  background: rgba(245, 158, 11, 0.2);
  color: #f59e0b;
}

.score-badge.needs-work {
  background: rgba(239, 68, 68, 0.2);
  color: #ef4444;
}

/* OmniScore Dashboard Card */
.omniscore-card {
  background: linear-gradient(135deg, var(--bg-card) 0%, #1a1a2e 100%);
  border: 1px solid var(--accent-primary);
  border-radius: var(--radius-lg);
  padding: 32px;
  display: flex;
  align-items: center;
  gap: 32px;
  box-shadow: var(--shadow-glow);
  margin-bottom: 32px;
}

.omniscore-card .omniscore-circle {
  width: 120px;
  height: 120px;
  flex-shrink: 0;
}

.omniscore-card .omniscore-circle::before {
  width: 100px;
  height: 100px;
}

.omniscore-card .omniscore-value {
  font-size: 36px;
}

.omniscore-details {
  flex: 1;
}

.omniscore-details h2 {
  font-family: var(--font-display);
  font-size: 24px;
  font-weight: 600;
  margin-bottom: 8px;
}

.omniscore-details p {
  color: var(--text-secondary);
  margin-bottom: 16px;
}

.omniscore-factors-mini {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 8px;
}

.factor-mini {
  display: flex;
  justify-content: space-between;
  font-size: 13px;
  padding: 6px 0;
  border-bottom: 1px solid var(--border-color);
}

.factor-mini:nth-child(odd) {
  border-right: 1px solid var(--border-color);
  padding-right: 12px;
}

.factor-mini:nth-child(even) {
  padding-left: 12px;
}

/* Responsive */
@media (max-width: 1024px) {
  .hero {
    flex-direction: column;
    text-align: center;
    padding-top: 120px;
  }

  .hero-cta {
    justify-content: center;
  }

  .hero-stats {
    justify-content: center;
  }

  .feature-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 768px) {
  .hero h1 {
    font-size: 42px;
  }

  .nav-links {
    display: none;
  }

  .feature-grid {
    grid-template-columns: 1fr;
  }

  .pricing-cards {
    grid-template-columns: 1fr;
  }

  .footer-content {
    flex-direction: column;
    gap: 40px;
  }

  .footer-links {
    gap: 40px;
  }
}

